import { CouponRepository } from "./coupon-repository";

export class CouponError extends Error {
  constructor(
    message: string,
    public readonly code: string
  ) {
    super(message);
    this.name = "CouponError";
  }
}

export class CouponService {
  constructor(private readonly repo: CouponRepository) {}

  /**
   * Applies a coupon to the given cart total.
   * @returns The discounted total after applying the coupon.
   * @throws CouponError with an appropriate error code if the coupon cannot be applied.
   */
  applyCoupon(cartTotal: number, couponCode: string): number {
    const coupon = this.repo.getCoupon(couponCode);

    if (coupon === null) {
      throw new CouponError(
        `Coupon code "${couponCode}" not found.`,
        "COUPON_NOT_FOUND"
      );
    }

    if (coupon.expired) {
      throw new CouponError(
        `Coupon code "${couponCode}" has expired.`,
        "COUPON_EXPIRED"
      );
    }

    if (coupon.minimumOrder !== undefined && cartTotal < coupon.minimumOrder) {
      throw new CouponError(
        `Order minimum of $${coupon.minimumOrder} not met. Cart total: $${cartTotal}.`,
        "ORDER_MINIMUM_NOT_MET"
      );
    }

    if (coupon.singleUse && coupon.used) {
      throw new CouponError(
        `Coupon code "${couponCode}" has already been used.`,
        "COUPON_ALREADY_USED"
      );
    }

    const discountMultiplier = 1 - coupon.discountPercent / 100;
    return cartTotal * discountMultiplier;
  }
}

